#include <iostream>

using namespace std;

struct Node
{
    int data;
    Node *next;
};

int main()
{
    Node *head = new Node{10, nullptr};
    Node *second = new Node{20, nullptr};
    Node *third = new Node{30, nullptr};

    head->next = second;
    second->next = third;
    third->next = head; // LOOPS BACK to head instead of nullptr

    Node *current = head;
    do
    {
        cout << current->data << " ";
        current = current->next;
    } while (current != head); // stop once we're back where we started

    return 0;
}

